	AddAnalyseNotificationCB(_pMRFSegmentPartitionDlg, _pMRFSegmentPartitionDlg->GetDiaAPPLYNotification(), (CATCommandMethod)& MRFSegmentPartitionCmd::OnApply, NULL);
	AddAnalyseNotificationCB(_pMRFSegmentPartitionDlg, _pMRFSegmentPartitionDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFSegmentPartitionCmd::ActionClose, NULL);

	CATListOfCATString List3DElements;
	List3DElements.Append("CATI3DGeometricalElement");

	CATListOfCATString ListPlanes;
	ListPlanes.Append("CATIGSMUsePlane");
	ListPlanes.Append("CATIMfPlane");



	CATDlgSelectorList* pSegmentCtngSetSelector = _pMRFSegmentPartitionDlg->GetSegmentCuttingSetSelector();
	_pSegmentCtngSetDialogAgent = new CATDialogAgent("SegmentCtngSetDialogAgent");
	if (!!_pSegmentCtngSetDialogAgent && NULL != pSegmentCtngSetSelector)
	{
		_pSegmentCtngSetDialogAgent->AcceptOnNotify(pSegmentCtngSetSelector, pSegmentCtngSetSelector->GetListSelectNotification());
	}

	CATDlgSelectorList* pTireAssySelector = _pMRFSegmentPartitionDlg->GetTireAssySelectorList();
	_pTireAssyDialogAgent = new CATDialogAgent("TireAssyDialogAgent");
