	{
		_pSegmentSetDialogAgent->AcceptOnNotify(pSegmentSetSelector, pSegmentSetSelector->GetListSelectNotification());
	}

	_pSegmentCtngSetPathElementAgent = new CATPathElementAgent("SegmentCtngSetPathElementAgent");
	if (_pSegmentCtngSetPathElementAgent)
	{
		_pSegmentCtngSetPathElementAgent->AddOrderedElementType("CATIBodyRequest");
		_pSegmentCtngSetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
	}

	_pTyrePathElementAgent = new CATPathElementAgent("TireAssyPathElementAgent");
	if (_pTyrePathElementAgent)
	{
		_pTyrePathElementAgent->SetOrderedTypeList(List3DElements);
		_pTyrePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
	}

	_pStartPlanePathElementAgent = new CATPathElementAgent("StartPlanePathElementAgent");
