	{
		_pStartPlanePathElementAgent->SetOrderedTypeList(ListPlanes);
		_pStartPlanePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
	}
	
	_pRefPlanePathElementAgent = new CATPathElementAgent("RefPlanePathElementAgent");
