//-------------------------------------------------------------------------
// OnApply ()
//-------------------------------------------------------------------------
void MRFSegmentPartitionCmd::OnApply(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pMRFSegmentPartitionDlg)
	{
		int selectedTab = _pMRFSegmentPartitionDlg->GetSelectedTab();
		if (0 == selectedTab)
		{
			if (!_bValidate && NULL_var == _spOGSTool)
			{
				CreateSegmentCuttingPlanes();
			}
			else
			{
				CATCommandClientData OnPlaneChange("OnPlaneChange");
				OnPlaneEditPush(ipCommand, ipNotification, OnPlaneChange);
			}				
		}
		else if (1 == selectedTab && NULL_var == _sp2DTyreLayout)
		{
			//Create2DLayoutPush();
			Create2DTyreLayout();
		}
		else if (2 == selectedTab && !_SegmentMode)
		{
			CreateSegmentSplits();
		}
		else if (3 == selectedTab)
		{
			ReverseDirection(ipCommand, ipNotification, iUsefulData);
		}


	}
	return;
}

//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFSegmentPartitionCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	OnApply(ipCommand, ipNotification, iUsefulData);
	RequestDelayedDestruction();
	return;
}

//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFSegmentPartitionCmd::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	RequestDelayedDestruction();
	
	return;
}

// Method to set the automatic angles when Number of Segments value is modified
void MRFSegmentPartitionCmd::SetSegmentAngleList(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pMRFSegmentPartitionDlg)
	{
		CATDlgSpinner * pNbSegments = _pMRFSegmentPartitionDlg->GetNbOfSegments();
		if (NULL != pNbSegments)
		{
			double NbSegments = pNbSegments->GetValue();
			int Nb = (int)NbSegments;

			_pMRFSegmentPartitionDlg->CreateNbOfSpinners(Nb);
			if (!_bValidate)
			{
				double angleToFill = 360. / NbSegments;

				for (int i = 1; i <= Nb; i++)
				{
					CATUnicodeString strIndex;
					strIndex.BuildFromNum(i);
					CATBaseUnknown * pSpinnerObject = _pListSpinners[i];
					if (NULL != pSpinnerObject)
					{
						CATDlgSpinner * pDlgSpinner = (CATDlgSpinner *)pSpinnerObject;
						if (NULL != pDlgSpinner && strIndex == pDlgSpinner->GetTitle() && CATDlgShow == pDlgSpinner->GetVisibility())
						{
							pDlgSpinner->SetCurrentValue((float)angleToFill, 0);
						}
					}
				}
			}
		}
		
	}
	return;
}

//Method run while creating segment cutting planes to validate the selections
CATBoolean MRFSegmentPartitionCmd::ValidateSelections()
{
	CATBoolean bValidate = CATTrue;
	if (bValidate && NULL != _pMRFSegmentPartitionDlg)
	{
		CATDlgSpinner * pNbSegments = _pMRFSegmentPartitionDlg->GetNbOfSegments();
		if (NULL != pNbSegments)
		{
			double NbSegments = pNbSegments->GetValue();
			int NbOfSegments = (int)NbSegments;
			if (NbOfSegments <= 0 || !ValidateAngles())
			{
				bValidate = CATFalse;
			}
		}
		if (bValidate)
		{
			CATDlgSpinner * pRefLength = _pMRFSegmentPartitionDlg->GetReferenceLength();
			if (NULL != pRefLength)
			{
				double dLength = (double)pRefLength->GetCurrentValue();

				if (dLength <= 0.)
					bValidate = CATFalse;
			}
			if (bValidate)
			{
				CATDlgSpinner * pRefWidth = _pMRFSegmentPartitionDlg->GetReferenceWidth();
				if (NULL != pRefWidth)
				{
					double dWidth = (double)pRefWidth->GetCurrentValue();

					if (dWidth <= 0.)
						bValidate = CATFalse;
				}
			}
		}
	}

	return bValidate;
}

//Method run tu validate the segment angles. If sum of angles more than 360, return false
CATBoolean MRFSegmentPartitionCmd::ValidateAngles()
{
	CATBoolean bVlidate = CATFalse;
	int NbOfSegments = 0;
	double AngleValue = 0.;
	_AngleList.RemoveAll();
	if (NULL != _pMRFSegmentPartitionDlg)
	{
		CATDlgSpinner * pNbSegments = _pMRFSegmentPartitionDlg->GetNbOfSegments();
		if (NULL != pNbSegments)
		{
			double NbSegments = pNbSegments->GetValue();
			NbOfSegments = (int)NbSegments;
		}

		CATDlgFrame * pPartitionFrame = _pMRFSegmentPartitionDlg->GetPartitionFrame();
		if (NULL != pPartitionFrame)
		{
			int ChildCount = pPartitionFrame->GetChildCount();
			ChildCount = ChildCount / 2;
			if (ChildCount > 0 && NbOfSegments <= ChildCount)
			{
				for (int i = 1; i < 2 * NbOfSegments; i++)
				{
					CATDialog * pChild = pPartitionFrame->GetChildFromChildNumber(i);
					if (NULL != pChild && CATDlgShow == pChild->GetVisibility())
					{
						CATDlgSpinner * pAngleSpinner = (CATDlgSpinner *) pChild;
						if (NULL != pAngleSpinner)
						{
							double Angle = (double)pAngleSpinner->GetCurrentValue();
							if (Angle > 0.)
							{
								_AngleList.Append(Angle);
								AngleValue = AngleValue + Angle;
							}
							else
								break;
						}						
					}
					i++;
				}
			}
		}
		
		if (round(AngleValue) == 360.)
			bVlidate = CATTrue;
	}

	return bVlidate;
}

//-------------------------------------------------------------------------
// MRFSegmentPartitionCmd::Show error message ()
//Input: CATUnicodeString usMessage, 
//Function: It displays the message sent as input as an error in Window.
//-------------------------------------------------------------------------
void MRFSegmentPartitionCmd::ShowErrorMessage(CATUnicodeString istrMessage)
{
	CATUnicodeString strWndTitle = "Invalid Input";

	if (NULL == _pApplicationFrame)
		_pApplicationFrame = CATApplicationFrame::GetFrame();

	if (NULL != _pApplicationFrame)
	{
		CATDlgWindow * pMainWindow = _pApplicationFrame->GetMainWindow();
		if (NULL != pMainWindow)
		{
			CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Error", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
			if (NULL != pErrPanel)
			{
				pErrPanel->DisplayBlocked(istrMessage, strWndTitle);
				AddAnalyseNotificationCB(pErrPanel, pErrPanel->GetNfyOKNotification(), (CATCommandMethod)&MRFSegmentPartitionCmd::ErrorPushOk, NULL);
			}
			if (pErrPanel)
				pErrPanel->RequestDelayedDestruction();
			pErrPanel = NULL;
		}
	}
}
//--------------------------------------------------------------------
// MRFSegmentPartitionCmd::ErrorPushOk
//Function: Destroy the error window created during error message displayed
//--------------------------------------------------------------------
void MRFSegmentPartitionCmd::ErrorPushOk(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	RequestDelayedDestruction();
}

