CATBoolean MRFSegmentPartitionCmd::OnPlaneSelection(void * iUsefulData)
{
	if (!!_pMRFSegmentPartitionDlg)
	{
		CATPathElementAgent * pPathElementAgent = NULL; 
		char * pstrAction = (char *)(CATCommandClientData)iUsefulData;
		CATString sAction(pstrAction);

		if (sAction == "RefPlaneData")
		{
			pPathElementAgent = _pRefPlanePathElementAgent;
		}
		else if (sAction == "StartPlaneData")
		{
			pPathElementAgent = _pStartPlanePathElementAgent;
		}
		if (NULL != pPathElementAgent)
		{
			CATPathElement * pPathElement = pPathElementAgent->GetValue();
			CATDlgSelectorList * pDlgSelector = NULL;
			CATDlgSelectorList * pNextDlgSelector = NULL;
			if (!!pPathElement)
			{
				if (NULL != _pHSO)
				{
					_pHSO->Empty();
				}
				if (sAction == "RefPlaneData")
				{
					pDlgSelector = _pMRFSegmentPartitionDlg->GetReferencePlane();
				}
				else if (sAction == "StartPlaneData")
				{
					pDlgSelector = _pMRFSegmentPartitionDlg->GetStartPlane();
				}
				_pMRFSegmentPartitionDlg->ClearAllSelections();
				if (NULL != pDlgSelector)
				{
					pDlgSelector->ClearLine();
					CATIMmiMechanicalFeature_var spPlaneObject = pPathElement->CurrentElement();
					if (!ValidateReferencePlaneSelection(spPlaneObject))
					{
						CATUnicodeString strMessage = "Invalid selection of Reference Plane\n";
						strMessage.Append("Selected plane is perpendicular to the selected axis of rotation.\n");
						strMessage.Append("Please change the axis of rotation or reselect the correct plane.");
						ShowErrorMessage(strMessage);
						pDlgSelector->SetLine("No Selection");
						pNextDlgSelector = pDlgSelector;
					}
					else
					{
						if (sAction == "RefPlaneData")
						{
							if (!!_pRefPlanePathElement)
								_pRefPlanePathElement->Release(); _pRefPlanePathElement = NULL;
							_pRefPlanePathElement = pPathElement;
							_pRefPlanePathElement->AddRef();
							pNextDlgSelector = _pMRFSegmentPartitionDlg->GetRefSurfaceSelector();
						}
						else if (sAction == "StartPlaneData")
						{
							if (!!_pStartPlanePathElement)
								_pStartPlanePathElement->Release(); _pStartPlanePathElement = NULL;
							_pStartPlanePathElement = pPathElement;
							_pStartPlanePathElement->AddRef();
							pNextDlgSelector = pDlgSelector;
						}

						if (NULL != _pHSO)
						{
							if (0 == _pHSO->IsMember(pPathElement))
								_pHSO->AddElement(pPathElement);
						}

						CATUnicodeString strPlaneName = "";
						if (NULL_var != spPlaneObject)
						{
							CATIAlias_var spAlias = spPlaneObject;
							if (NULL_var != spAlias)
							{
								strPlaneName = spAlias->GetAlias();
							}

							if (sAction == "RefPlaneData")
							{
								if (NULL_var != _spReferencePlane)
									_spReferencePlane = NULL_var;

								_spReferencePlane = spPlaneObject;
							}
							else if (sAction == "StartPlaneData")
							{
								if (NULL_var != _spStartPlane)
									_spStartPlane = NULL_var;

								_spStartPlane = spPlaneObject;
							}
							pDlgSelector->SetLine(strPlaneName);
						}
						UpdatePlaneSelectors();
					}
					if (NULL != pNextDlgSelector)
						_pMRFSegmentPartitionDlg->SetFocusOnSelectorList(pNextDlgSelector);
				}
			}
			pPathElementAgent->InitializeAcquisition();
		}
	}
	return TRUE;
}

