			CATICkeParm_var spThirdPtOrigin = spCkeFact->CreateReal("OriginZ", iPtrPoint[2]);

			CATIGSMUsePointCoord_var spGSMPoint = _spGSMFactory->CreatePoint(spFirstPtOrigin, spSecondPtOrigin, spThirdPtOrigin);
