void MRFSegmentPartitionCmd::UpdateFeatureTree(CATIMmiMechanicalFeature_var iMechanicalFeature, CATIMmiMechanicalFeature_var ispFatherFeature)
{
	if (NULL_var == ispFatherFeature)
	{
		CATIPartRequest * pPartRequest = NULL;
		_spMechanicalPart->QueryInterface(IID_CATIPartRequest, (void**)&pPartRequest);
		if (NULL != pPartRequest)
		{
			CATBaseUnknown_var spPartBody;
			pPartRequest->GetMainBody("MfDefault3DView",spPartBody);
			if (NULL_var != spPartBody)
			{
				ispFatherFeature = spPartBody;
			}
			pPartRequest->Release(); pPartRequest = NULL;
		}
	}
	if (NULL_var != ispFatherFeature)
	{
		if (NULL_var == _spMainBody)
			_spMainBody = ispFatherFeature;

		CATIMmiUseBasicInsertion_var spBasicInsertion = iMechanicalFeature;
		if (NULL_var != spBasicInsertion)
			spBasicInsertion->InsertInside(ispFatherFeature);

		CATIModelEvents_var MyFeatureModelEventsTool = ispFatherFeature;
		CATModify NotifModify(ispFatherFeature);
		MyFeatureModelEventsTool->Dispatch(NotifModify);

		CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(ispFatherFeature, 0, 0);

		CATIMmiUsePrtPart * piPrtPart = NULL;
		_spMechanicalPart->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
		if (NULL != piPrtPart)
		{
			piPrtPart->SetInWorkObject(iMechanicalFeature);
			piPrtPart->Release(); piPrtPart = NULL;
		}
	}

}

