CATBoolean MRFSegmentPartitionCmd::OnSurfaceSelection(void * iData)
{
	if (!!_pMRFSegmentPartitionDlg)
	{
		CATPathElementAgent * pPathElementAgent = NULL;
		char * pstrAction = (char *)(CATCommandClientData)iData;
		CATString sAction(pstrAction);

		if (sAction == "RefSurface")
		{
			pPathElementAgent = _pRefSurfacePathElementAgent;
		}
		else if (sAction == "RefCurve")
		{
			pPathElementAgent = _pRefCurvePathElementAgent;
		}
		if (NULL != pPathElementAgent)
		{
			CATPathElement * pPathElement = pPathElementAgent->GetValue();
			CATDlgSelectorList * pDlgSelector = NULL;
			CATDlgSelectorList * pNextDlgSelector = NULL;
			if (!!pPathElement)
			{
				CATUnicodeString strSurfaceName = "";
				CATIMmiMechanicalFeature_var spSurfaceObject = pPathElement->CurrentElement();
				if (NULL != _pHSO)
				{
					_pHSO->Empty();
					if (NULL_var != _spReferenceCurve)
						_spReferenceCurve = NULL_var;
					if (NULL_var != _spReferenceSurface)
						_spReferenceSurface = NULL_var;

					if (NULL_var != spSurfaceObject && ValidateReferenceSurface(spSurfaceObject))
					{
						if (sAction == "RefSurface")
						{
							pDlgSelector = _pMRFSegmentPartitionDlg->GetRefSurfaceSelector();
							_pRefSurfacePathElement = pPathElement;
							_spReferenceSurface = spSurfaceObject;
							/*if (ValidateReferenceSurface(spSurfaceObject))
							{
								_pRefSurfacePathElement = pPathElement;
								_spReferenceSurface = spSurfaceObject;
							}
							else if (!!_pRefSurfacePathElement)
							{
								_pRefSurfacePathElement = NULL;
								pPathElement = NULL;
							}*/
						}
						else if (sAction == "RefCurve")
						{
							pDlgSelector = _pMRFSegmentPartitionDlg->GetRefCurveSelector();
							_pRefCurvePathElement = pPathElement;
							_spReferenceCurve = spSurfaceObject;
						}
						CATIAlias_var spAlias = spSurfaceObject;
						if (NULL_var != spAlias)
						{
							strSurfaceName = spAlias->GetAlias();
						}
						_pHSO->AddElement(pPathElement);
						UpdateCurveSelectors();
					}
					else
					{
						pPathElement = NULL;
						if (!!_pRefSurfacePathElement)
							_pRefSurfacePathElement = NULL;
						if (!!_pRefCurvePathElement)
							_pRefCurvePathElement = NULL;
						strSurfaceName = "No Selection";
					}
				}
				_pMRFSegmentPartitionDlg->ClearAllSelections();
				if (NULL != pDlgSelector)
				{
					pDlgSelector->ClearLine();
					pDlgSelector->SetLine(strSurfaceName);
					_pMRFSegmentPartitionDlg->SetFocusOnSelectorList(pDlgSelector);
				}
			}
			pPathElementAgent->InitializeAcquisition();
		}
	}
	return TRUE;
}

