//Method to set the position of mainpulator at the time or release from the manipulator. Call back on manipulator
void MRFSegmentPartitionCmd::UpdateAnglesFromPlanes(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	int NbPlanes = _spList2DPlanes.Size();
	if (NbPlanes > 0)
	{
		CATDlgSpinner * pDlgSpinner = NULL;
		for (int i = 1; i < NbPlanes; i++)
		{
			if (i == 1)
			{
				pDlgSpinner = _pMRFSegmentPartitionDlg->GetStartAngle();
			}
			else
			{
				pDlgSpinner = (CATDlgSpinner *)_pListSpinners[i - 1];
			}
			CATIGSMUsePlaneOffset_var spPlane = _spList2DPlanes[i];
			if (NULL_var != spPlane && NULL != pDlgSpinner && CATDlgShow == pDlgSpinner->GetVisibility())
			{
				CATICkeParm_var spOffsetParam;
				spPlane->GetOffset(spOffsetParam);
				if (NULL_var != spOffsetParam)
				{
					double offValue = 0.;
					CATUnicodeString strOffsetValue = spOffsetParam->Show();
					strOffsetValue.ConvertToNum(&offValue);

					double angle = (offValue / _d2DTotalLength) * 360.;
					float value = (float)round(angle);
					pDlgSpinner->SetCurrentValue(value, 1);
				}
			}
		}
		//DisplayPlaneIntersect();
	}
	if (NULL != iUsefulData)
	{
		char * pstrAction = (char *)iUsefulData;
		CATString sAction(pstrAction);
		if (sAction == "FromManip")
		{
			CATDlgCombo * pPlaneToEditCombo = _pMRFSegmentPartitionDlg->GetPlaneCombo();
			if (!!pPlaneToEditCombo)
			{
				int index = pPlaneToEditCombo->GetSelect();
				if (index >= 0)
				{
					pPlaneToEditCombo->SetSelect(index, 1);
				}
			}
		}
	}

	return;
}
/**
* Display Axis in 3D based on the user selection of rotation axis
*/
void MRFSegmentPartitionCmd::DisplayAxis(int iIndex)
{
	if (!!_pMRFSegmentPartitionDlg && !!_pAxisModel && !!_pISO && iIndex >= 0)
	{
		_pAxisModel->UnreferenceRep();
		_pISO->RemoveElement(_pAxisModel);

		int index = iIndex;
		CATMathPointf MathPointF;

		float StartPoint[3] = { 0.f, 0.f, 0.f };
		float EndPoint[3] = { 0.f, 0.f, 0.f };

		StartPoint[index] = -1000.f;
		EndPoint[index] = 1000.f;

		float iPoints[6] = { StartPoint[0],StartPoint[1], StartPoint[2], EndPoint[0], EndPoint[1], EndPoint[2] };

		CAT3DLineGP * pLineGP = new CAT3DLineGP(iPoints);
		if (NULL != pLineGP)
		{
			CATGraphicAttributeSet AttributeSet;
			AttributeSet.SetColor(GREEN);
			AttributeSet.SetFixedThickness(3);
			AttributeSet.SetLineType(7);

			CAT3DCustomRep * pAxisRep = CAT3DCustomRep::CreateRep();
			if (NULL != pAxisRep)
			{
				pAxisRep->AddGP(pLineGP, AttributeSet);

				CAT3DBoundingSphere be(MathPointF, 0.f, 1.f);
				pAxisRep->SetBoundingElement(be);

				_pAxisModel->SetRep(pAxisRep);
				_pISO->AddElement(_pAxisModel);
			}
		}
	}
}
